/**
 * Send a notification through the appropriate adapter.
 * Notifications for the same recipient are queued to ensure delivery order.
 * Falls back to in-memory storage if no adapter is registered for the channel.
 */
async sendNotification(payload: NotificationPayload): Promise<void> {
  const recipient = payload.recipient;
  const previous = this.recipientQueues.get(recipient) ?? Promise.resolve();
  const current = previous.then(() => this.deliverNotification(payload));
  this.recipientQueues.set(recipient, current.catch(() => {}));
  return current;
}

/**
 * Internal: perform the actual notification delivery.
 */
private async deliverNotification(payload: NotificationPayload): Promise<void> {
  if (this.preferencesService) {
    const userId = payload.metadata?.userId as string | undefined ?? payload.recipient;
    if (!this.preferencesService.shouldSendNotification(userId, payload.type, payload.channel)) {
      this.logger.info(
        `Notification suppressed by user preferences: ${payload.type} (${payload.channel}) for ${userId}`,
      );
      return;
    }
  }

  const id = generateNotificationId();
  const adapter = this.adapters.get(payload.channel);

  let status: 'sent' | 'failed' = 'sent';

  if (adapter) {
    const result = await adapter.send(payload);
    if (!result.success) {
      this.logger.error(`Adapter failed for ${payload.channel}: ${result.error}`);
      status = 'failed';
    }
  } else {
    this.logger.info(`No adapter for channel ${payload.channel}, storing notification in-memory`);
  }

  const notification: Notification = {
    id,
    type: payload.type,
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    channel: payload.channel,
    status,
    sentAt: new Date(),
    metadata: payload.metadata,
  };

  this.notifications.push(notification);

  if (this.historyService) {
    this.historyService.log(notification);
  }

  this.logger.info(`Notification ${status}: ${id} to ${payload.recipient}`);
}

